function ReadingList() {
  const [books, setBooks] = React.useState([
    { title: 'The Design of Everyday Things', author: 'Don Norman', progress: 65, status: 'reading' },
    { title: 'Atomic Habits', author: 'James Clear', progress: 30, status: 'reading' },
    { title: 'Deep Work', author: 'Cal Newport', progress: 100, status: 'finished' }
  ]);
  const [newTitle, setNewTitle] = React.useState('');
  const [newAuthor, setNewAuthor] = React.useState('');

  function addBook() {
    if (!newTitle.trim()) return;
    setBooks([...books, { title: newTitle, author: newAuthor || 'Unknown', progress: 0, status: 'reading' }]);
    setNewTitle('');
    setNewAuthor('');
  }

  function updateProgress(idx, delta) {
    setBooks(books.map((b, i) => {
      if (i !== idx) return b;
      const p = Math.max(0, Math.min(100, b.progress + delta));
      return { ...b, progress: p, status: p === 100 ? 'finished' : 'reading' };
    }));
  }

  function removeBook(idx) {
    setBooks(books.filter((_, i) => i !== idx));
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#fff', borderRadius: 12, height: '100%', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
      <h2 style={{ margin: '0 0 12px 0', fontSize: 18, color: '#1a1a1a' }}>Reading List</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        <input placeholder="Title" value={newTitle} onChange={e => setNewTitle(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <input placeholder="Author" value={newAuthor} onChange={e => setNewAuthor(e.target.value)} style={{ flex: 1, padding: '6px 10px', borderRadius: 6, border: '1px solid #ddd', fontSize: 13 }} />
        <button onClick={addBook} style={{ padding: '6px 14px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Add</button>
      </div>
      <div style={{ flex: 1, overflowY: 'auto' }}>
        {books.map((book, i) => (
          <div key={i} style={{ marginBottom: 12, padding: 12, borderRadius: 8, background: '#f8f9fa' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 14, color: '#1a1a1a' }}>{book.title}</div>
                <div style={{ fontSize: 12, color: '#666' }}>{book.author}</div>
              </div>
              <button onClick={() => removeBook(i)} style={{ background: 'transparent', border: 'none', color: '#999', cursor: 'pointer', fontSize: 16 }}>x</button>
            </div>
            <div style={{ marginTop: 8, display: 'flex', alignItems: 'center', gap: 8 }}>
              <div style={{ flex: 1, height: 8, background: '#e5e7eb', borderRadius: 4, overflow: 'hidden' }}>
                <div style={{ width: book.progress + '%', height: '100%', background: book.status === 'finished' ? '#22c55e' : '#2563eb', borderRadius: 4, transition: 'width 0.3s' }} />
              </div>
              <span style={{ fontSize: 12, color: '#555', minWidth: 32 }}>{book.progress}%</span>
              <button onClick={() => updateProgress(i, -10)} style={{ padding: '2px 8px', borderRadius: 4, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 12 }}>-</button>
              <button onClick={() => updateProgress(i, 10)} style={{ padding: '2px 8px', borderRadius: 4, border: '1px solid #ddd', background: '#fff', cursor: 'pointer', fontSize: 12 }}>+</button>
            </div>
          </div>
        ))}
        {books.length === 0 && <div style={{ textAlign: 'center', color: '#999', fontSize: 13, padding: 20 }}>No books yet. Add one above!</div>}
      </div>
    </div>
  );
}
render(<ReadingList/>);
